        // Section 4 (60-80): dense challenge
        MakePlatform(plat, 63, 2, 2, "brick_brown");
        MakePlatform(plat, 66, 2, 6, "brick_brown", true);  // pillar
        MakePlatform(plat, 72, 3, 4, "brick_grey");
