#### `E:\unity\projs\final_proj\Assets\Scripts\FoodItem.cs`

Collectible food items on triggers. Adds sugar + hunger to `StatusUI`, then self-destructs.

```csharp
using UnityEngine;

public class FoodItem : MonoBehaviour
{
    [Header("Stats")]
    public float sugarBonus = 10f;
    public float hungerBonus = 10f;

    void Awake()
    {
        if (GetComponent<Collider2D>() == null)
        {
            CircleCollider2D col = gameObject.AddComponent<CircleCollider2D>();
            col.isTrigger = true;
            col.radius = 0.5f;
        }
    }

    void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player"))
            return;

        StatusUI status = FindObjectOfType<StatusUI>();
        if (status != null)
        {
            status.AddSugar(sugarBonus);
            status.AddHunger(hungerBonus);
        }

        Destroy(gameObject);
    }
}
```

#### `E:\unity\projs\final_proj\Assets\Scripts\PotionItem.cs`

Collectible potion items. Calls `PlayerController.AddPotion()` on pickup (up to 3 max), then self-destructs.

```csharp
using UnityEngine;

public class PotionItem : MonoBehaviour
{
    void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player"))
            return;

        var pc = other.GetComponent<PlayerController>();
        if (pc != null && pc.AddPotion())
            Destroy(gameObject);
    }
}
